from itertools import combinations
class Solution:
    def minRemovals(self, nums, target):
        n = len(nums)
        total = 0
        for x in nums:
            total ^= x
        need = total ^ target
        for size in range(0, n + 1):
            for combo in combinations(nums, size):
                x = 0
                for v in combo:
                    x ^= v
                if x == need:
                    return size
        return -1

