class Solution:
    def minRemovals(self, nums, target):
        total = 0
        for x in nums:
            total ^= x
        need = total ^ target
        dp = {0: 0}
        for x in nums:
            new_dp = dict(dp)
            for xv, cnt in dp.items():
                nx = xv ^ x
                nc = cnt + 1
                if nx not in new_dp or new_dp[nx] > nc:
                    new_dp[nx] = nc
            dp = new_dp
        return dp.get(need, -1)

