var minRemovals = function(nums, target) {
    let total = 0;
    for (const x of nums) total ^= x;
    const need = total ^ target;
    let dp = new Map([[0, 0]]);
    for (const x of nums) {
        const newDp = new Map(dp);
        for (const [xv, cnt] of dp) {
            const nx = xv ^ x;
            const nc = cnt + 1;
            if (!newDp.has(nx) || newDp.get(nx) > nc) newDp.set(nx, nc);
        }
        dp = newDp;
    }
    return dp.has(need) ? dp.get(need) : -1;
};
